"""
handwriting_sheet.py — WFA Year 4 Handwriting Practice Generator
=================================================================

Generates handwriting practice PDFs in two versions:
  - XCCW cursive (solid or dotted, 26pt, 8mm ascenders)
  - Sassoon Infant dotted print (31.8pt, 8mm ascenders)

All fonts are embedded as base64 — no external font files needed.

XCCW JOIN RULE:
  A character uses font 4b if the PREVIOUS character is o, r, v, w, or x (top exit).
  Otherwise uses 4a. First character always 4a.

USAGE:
  import handwriting_sheet as hs

  # Word sheet
  hs.make_sheet(
      words=['river', 'every', 'morning'],
      output_xccw='out-xccw.pdf',
      output_sassoon='out-sassoon.pdf',
      title='Handwriting Practice',
      xccw_style='dotted',   # 'dotted' or 'solid'
  )

  # Sentence sheet
  hs.make_sheet(
      sentences=['The Maya built big pyramids.'],
      output_xccw='out-xccw.pdf',
      output_sassoon='out-sassoon.pdf',
      title='Mayan Sentences',
      xccw_style='dotted',
  )

  # Join practice sheet
  hs.make_join_sheet(
      letter='r',
      pairs=['ra  re  ri  ro  ru', 'rn  rm  rt  rl  ry'],
      words=['river', 'every', 'morning'],
      output_xccw='joins-r-xccw.pdf',
      output_sassoon='joins-r-sassoon.pdf',
      xccw_style='dotted',
  )

  # Check widths before generating sentences
  hs.check_widths(['The Maya built big pyramids.', 'They grew maize to eat.'])

DEPENDENCIES:
  pip install reportlab --break-system-packages
"""

