_FONTS_REGISTERED = set()

def _ensure_fonts():
    global _FONT_DIR
    if _FONT_DIR is None:
        _FONT_DIR = tempfile.mkdtemp(prefix='wfa_fonts_')
        atexit.register(shutil.rmtree, _FONT_DIR, ignore_errors=True)
    for name, b64_parts in _FONTS.items():
        if name not in _FONTS_REGISTERED:
            path = os.path.join(_FONT_DIR, f'{name}.ttf')
            with open(path, 'wb') as f:
                f.write(base64.b64decode(''.join(b64_parts) if isinstance(b64_parts, tuple) else b64_parts))
            pdfmetrics.registerFont(TTFont(name, path))
            _FONTS_REGISTERED.add(name)

# ── Constants ─────────────────────────────────────────────────────────────────

TOP_EXIT = set('orvwx')
W, H     = A4
MARGIN   = 50
LINE_W   = W - MARGIN * 2
MM       = 72 / 25.4

# XCCW: 26pt gives ascenders of 8.07mm, descenders 3.55mm
XCCW_FS      = 26
XCCW_ASCEND  = 8.07 * MM
XCCW_DESCEND = 3.55 * MM

# Sassoon Infant Dotted: 31.8pt gives ascenders of 8.00mm, descenders 3.33mm
SASS_FS      = 31.8
SASS_ASCEND  = 8.00 * MM
SASS_DESCEND = 3.33 * MM

# Linkpen Pre-cursive Dotted: 21pt gives ascenders of 9.04mm, descenders 3.26mm
LINK_FS      = 21
LINK_ASCEND  = 9.0434 * MM
LINK_DESCEND = 3.2556 * MM

ROW_GAP  = 2.5 * MM   # gap between descender of one row and top line of next
WORD_GAP = 2.0 * MM   # extra space between word blocks

NAVY  = (14/255,  40/255,  65/255)
TEAL  = (21/255,  96/255, 130/255)
LGREY = (0.78, 0.78, 0.78)
MGREY = (0.60, 0.60, 0.60)
BG    = (0.87, 0.93, 0.97)
AMBER = (1.0, 0.98, 0.92)

# ── Internal helpers ──────────────────────────────────────────────────────────

def _xccw_font_for(ch, prev):
    """Return correct XCCW font name for character given previous character."""
    if prev and prev.lower() in TOP_EXIT:
        return 'XCCW_Joined_Dotted_4b'
    return 'XCCW_Joined_Dotted_4a'

def _xccw_font_for_solid(ch, prev):
    if prev and prev.lower() in TOP_EXIT:
        return 'XCCW_Joined_4b'
    return 'XCCW_Joined_4a'

def _draw_xccw(c, x, y, text, size, solid=False):
    fn = _xccw_font_for_solid if solid else _xccw_font_for
    for i, ch in enumerate(text):
        prev = text[i-1] if i > 0 else None
        font = fn(ch, prev)
        c.setFont(font, size)
        c.setFillColorRGB(*NAVY)
        c.drawString(x, y, ch)
        x += c.stringWidth(ch, font, size)

def _draw_sassoon(c, x, y, text, size):
    c.setFont('SassoInfDotB', size)
    c.setFillColorRGB(*NAVY)
    c.drawString(x, y, text)

def _draw_linkpen(c, x, y, text, size):
    c.setFont('LinkpenDot', size)
    c.setFillColorRGB(*NAVY)
    c.drawString(x, y, text)

def _draw_ruled_row(c, baseline_y, ascend, descend, tint=False):
    """Draw top line + baseline. Optional amber tint for join pair rows."""
    if tint:
        c.setFillColorRGB(*AMBER)
        c.rect(MARGIN, baseline_y - descend, LINE_W, ascend + descend + 2, fill=1, stroke=0)
    top_y = baseline_y + ascend
    c.setStrokeColorRGB(0.80, 0.80, 0.80)
    c.setLineWidth(0.5)
    c.setDash()
    c.line(MARGIN, top_y, MARGIN + LINE_W, top_y)
    c.setStrokeColorRGB(*LGREY)
    c.setLineWidth(0.8)
    c.line(MARGIN, baseline_y, MARGIN + LINE_W, baseline_y)

def _draw_header(c, title, subtitle=None):
    header_h = 60 if subtitle else 50
    c.setFillColorRGB(*BG)
    c.rect(0, H - header_h, W, header_h, fill=1, stroke=0)
    c.setFillColorRGB(*TEAL)
    c.setFont('Helvetica-Bold', 13)
    c.drawString(MARGIN, H - 21, title)
    c.setFillColorRGB(*MGREY)
    c.setFont('Helvetica', 9)
    if subtitle:
        c.drawString(MARGIN, H - 35, subtitle)
        c.drawString(MARGIN, H - 52, 'Trace each item, then continue writing it on the rest of the line.')
    else:
        c.drawString(MARGIN, H - 37, 'Trace each item, then continue writing it on the rest of the line.')
    c.setFillColorRGB(*NAVY)
    c.setFont('Helvetica', 9)
    c.drawRightString(W - MARGIN - 124, H - 21, 'Name:')
    c.setStrokeColorRGB(*LGREY)
    c.setLineWidth(0.8)
    c.setDash()
    c.line(W - MARGIN - 120, H - 21, W - MARGIN, H - 21)
    return header_h

def _xccw_text_width(text, solid=False, size=None):
    """Measure XCCW text width using a temporary canvas."""
    if size is None:
        size = XCCW_FS
    _ensure_fonts()
    tmp = canvas.Canvas('/dev/null', pagesize=A4)
    fn = _xccw_font_for_solid if solid else _xccw_font_for
    x = 0
    for i, ch in enumerate(text):
        prev = text[i-1] if i > 0 else None
        font = fn(ch, prev)
        tmp.setFont(font, size)
        x += tmp.stringWidth(ch, font, size)
    return x

def _sass_text_width(text, size=None):
    if size is None:
        size = SASS_FS
    _ensure_fonts()
    tmp = canvas.Canvas('/dev/null', pagesize=A4)
    tmp.setFont('SassoInfDotB', size)
    return tmp.stringWidth(text, 'SassoInfDotB', size)

# ── Public helpers ────────────────────────────────────────────────────────────

def check_widths(items, solid=False):
    """
    Print width check for a list of words or sentences.
    Returns list of items that are too long for XCCW at current font size.
    """
    _ensure_fonts()
    too_long = []
    print(f"Width check (XCCW max {LINE_W:.0f}pt, Sassoon max {LINE_W:.0f}pt):")
    for item in items:
        xw = _xccw_text_width(item, solid=solid)
        sw = _sass_text_width(item)
        flag = ' *** TOO LONG FOR XCCW ***' if xw > LINE_W else ''
        sflag = ' *** TOO LONG FOR SASSOON ***' if sw > LINE_W else ''
        print(f"  xccw={xw:.0f}pt sass={sw:.0f}pt  {item}{flag}{sflag}")
        if xw > LINE_W:
            too_long.append(item)
    return too_long

# ── Core sheet generators ─────────────────────────────────────────────────────

def _generate_pdf(output_path, rows, title, subtitle, ascend, descend, draw_fn, font_size, practice_lines=0):
    """
    Internal: generate a PDF from a list of row dicts.
    Each row: {'type': 'word'|'pairs', 'text': str}
    practice_lines: blank ruled lines to draw after each content row.
    """
    row_h = ascend + descend + ROW_GAP
    c     = canvas.Canvas(output_path, pagesize=A4)
    hdr_h = _draw_header(c, title, subtitle)
    y     = H - hdr_h - 10 - ascend

    def _check_page(cur_y):
        if cur_y - descend < MARGIN:
            c.showPage()
            new_hdr = _draw_header(c, title, subtitle)
            return H - new_hdr - 10 - ascend
        return cur_y

    for row in rows:
        is_pairs = row['type'] == 'pairs'
        y = _check_page(y)
        _draw_ruled_row(c, y, ascend, descend, tint=is_pairs)
        draw_fn(c, MARGIN, y, row['text'], font_size)
        y -= row_h + WORD_GAP
        for _ in range(practice_lines):
            y = _check_page(y)
            _draw_ruled_row(c, y, ascend, descend)
            y -= row_h + WORD_GAP

    c.save()
    print(f'Saved: {output_path}')


def make_sheet(
    words=None,
    sentences=None,
    output_xccw='output-xccw.pdf',
    output_sassoon='output-sassoon.pdf',
    title='Year 4 Handwriting Practice',
    subtitle=None,
    xccw_style='dotted',
):
    """
    Generate both XCCW and Sassoon handwriting sheets.

    Pass either `words` (list of str) or `sentences` (list of str), not both.
    xccw_style: 'dotted' or 'solid'
    """
    _ensure_fonts()
    items = words if words is not None else sentences
    if items is None:
        raise ValueError('Provide either words= or sentences=')

    rows = [{'type': 'word', 'text': item} for item in items]

    solid = (xccw_style == 'solid')
    xccw_draw = lambda c, x, y, text, size: _draw_xccw(c, x, y, text, size, solid=solid)

    _generate_pdf(output_xccw,   rows, title, subtitle, XCCW_ASCEND, XCCW_DESCEND, xccw_draw,  XCCW_FS)
    _generate_pdf(output_sassoon, rows, title, subtitle, SASS_ASCEND, SASS_DESCEND, _draw_sassoon, SASS_FS)


def make_join_sheet(
    letter,
    pairs,
    words,
    output_xccw='joins-xccw.pdf',
    output_sassoon='joins-sassoon.pdf',
    xccw_style='dotted',
):
    """
    Generate a join practice sheet for a single top-exit letter.

    letter: str, e.g. 'r'
    pairs:  list of str, e.g. ['ra  re  ri  ro  ru', 'rn  rm  rt  rl  ry']
    words:  list of str — curriculum words practising this join
    xccw_style: 'dotted' or 'solid'
    """
    _ensure_fonts()
    rows = (
        [{'type': 'pairs', 'text': p} for p in pairs] +
        [{'type': 'word',  'text': w} for w in words]
    )
    title    = f'Join Practice — the {letter} join'
    subtitle = f'{letter} has a top exit, so the letter after {letter} always joins from the top'

    solid    = (xccw_style == 'solid')
    xccw_draw = lambda c, x, y, text, size: _draw_xccw(c, x, y, text, size, solid=solid)

    _generate_pdf(output_xccw,    rows, title, subtitle, XCCW_ASCEND, XCCW_DESCEND, xccw_draw,    XCCW_FS)
    _generate_pdf(output_sassoon, rows, title, subtitle, SASS_ASCEND, SASS_DESCEND, _draw_sassoon, SASS_FS)


# ── CLI demo ──────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    make_sheet(
        words=['river', 'every', 'morning', 'dragon', 'orange', 'spring'],
        output_xccw='/tmp/demo-xccw.pdf',
        output_sassoon='/tmp/demo-sassoon.pdf',
        title='Handwriting Demo',
        xccw_style='dotted',
    )
    print('Demo PDFs written to /tmp/')
